import React from 'react';
import {
  Drawer,
  Box,
  Typography,
  IconButton,
  Chip,
  Divider,
  Link,
  Stack,
  Tooltip,
} from '@mui/material';
import CloseIcon from '@mui/icons-material/Close';
import OpenInNewIcon from '@mui/icons-material/OpenInNew';
import ThumbUpIcon from '@mui/icons-material/ThumbUp';
import ChatBubbleOutlineIcon from '@mui/icons-material/ChatBubbleOutline';
import type { Comment } from '@/shared/types/comment';
import {
  COMMENT_TYPE_LABELS,
  COMMENT_TYPE_COLORS,
  SENTIMENT_LABELS,
  SENTIMENT_COLORS,
  CATEGORY_LABELS,
} from '@/shared/constants/labels';
import dayjs from 'dayjs';

interface CommentDetailDrawerProps {
  open: boolean;
  comment: Comment | null;
  onClose: () => void;
}

/** Detailed info row */
const InfoRow: React.FC<{ label: string; children: React.ReactNode }> = ({
  label,
  children,
}) => (
  <Box sx={{ display: 'flex', mb: 1 }}>
    <Typography
      variant="body2"
      color="text.secondary"
      sx={{ minWidth: 90, flexShrink: 0 }}
    >
      {label}
    </Typography>
    <Box sx={{ flexGrow: 1 }}>{children}</Box>
  </Box>
);

/** Detail drawer showing complete comment information */
const CommentDetailDrawer: React.FC<CommentDetailDrawerProps> = ({
  open,
  comment,
  onClose,
}) => {
  if (!comment) return null;

  return (
    <Drawer
      anchor="right"
      open={open}
      onClose={onClose}
      PaperProps={{
        sx: {
          width: { xs: '100%', sm: 480 },
          p: 3,
          bgcolor: 'background.paper',
        },
      }}
    >
      {/* Header */}
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          mb: 2,
        }}
      >
        <Typography variant="h6" fontWeight={700}>
          评论详情
        </Typography>
        <IconButton onClick={onClose} size="small">
          <CloseIcon />
        </IconButton>
      </Box>

      <Divider sx={{ mb: 2 }} />

      {/* Comment content */}
      <Box
        sx={{
          p: 2,
          mb: 2,
          borderRadius: 2,
          bgcolor: 'action.hover',
          border: '1px solid',
          borderColor: 'divider',
        }}
      >
        <Typography variant="body1" sx={{ whiteSpace: 'pre-wrap', lineHeight: 1.7 }}>
          {comment.content}
        </Typography>
      </Box>

      {/* Labels */}
      {(comment.labels || []).length > 0 && (
        <Box sx={{ mb: 2 }}>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
            标签
          </Typography>
          <Stack direction="row" spacing={0.5} flexWrap="wrap" useFlexGap>
            {comment.labels.map((label) => (
              <Chip
                key={label}
                label={label}
                size="small"
                variant="outlined"
                sx={{ mb: 0.5 }}
              />
            ))}
          </Stack>
        </Box>
      )}

      <Divider sx={{ mb: 2 }} />

      {/* Basic info */}
      <Box>
        <InfoRow label="ID">
          <Typography variant="body2" fontFamily="monospace" fontSize={12}>
            #{comment.id}
          </Typography>
        </InfoRow>
        <InfoRow label="平台">
          <Chip
            label={comment.platform}
            size="small"
            variant="outlined"
            sx={{ fontSize: 11 }}
          />
        </InfoRow>
        <InfoRow label="作者">
          <Typography variant="body2">{comment.userName || '匿名用户'}</Typography>
        </InfoRow>
        <InfoRow label="抖音号">
          <Typography variant="body2">
            {comment.douyinId || '—'}
          </Typography>
        </InfoRow>
        <InfoRow label="类型">
          <Chip
            label={COMMENT_TYPE_LABELS[comment.type] || comment.type}
            size="small"
            color={COMMENT_TYPE_COLORS[comment.type] || 'default'}
            sx={{ fontSize: 11 }}
          />
        </InfoRow>
        <InfoRow label="情感">
          <Chip
            label={SENTIMENT_LABELS[comment.sentiment] || comment.sentiment}
            size="small"
            color={SENTIMENT_COLORS[comment.sentiment] || 'default'}
            variant="outlined"
            sx={{ fontSize: 11 }}
          />
        </InfoRow>
        <InfoRow label="分类">
          <Typography variant="body2">
            {CATEGORY_LABELS[comment.category] || comment.category || '—'}
          </Typography>
        </InfoRow>
        <InfoRow label="时间">
          <Typography variant="body2">
            {comment.date
              ? dayjs(comment.date).format('YYYY-MM-DD HH:mm:ss')
              : '—'}
          </Typography>
        </InfoRow>
        <InfoRow label="IP 属地">
          <Typography variant="body2">{comment.ipAddress || '—'}</Typography>
        </InfoRow>

        {/* Stats */}
        <Stack direction="row" spacing={3} sx={{ mb: 1, ml: 11 }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
            <ThumbUpIcon sx={{ fontSize: 16, color: 'text.secondary' }} />
            <Typography variant="body2">{comment.likes || 0}</Typography>
          </Box>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
            <ChatBubbleOutlineIcon
              sx={{ fontSize: 16, color: 'text.secondary' }}
            />
            <Typography variant="body2">
              {comment.subCommentCount || 0}
            </Typography>
          </Box>
        </Stack>

        {/* Video link */}
        {comment.videoLink && (
          <InfoRow label="视频链接">
            <Link
              href={comment.videoLink}
              target="_blank"
              rel="noopener noreferrer"
              underline="hover"
              sx={{ display: 'inline-flex', alignItems: 'center', gap: 0.5 }}
            >
              <Typography variant="body2" noWrap sx={{ maxWidth: 280 }}>
                {comment.videoLink}
              </Typography>
              <OpenInNewIcon sx={{ fontSize: 14 }} />
            </Link>
          </InfoRow>
        )}
        {comment.videoId && !comment.videoLink && (
          <InfoRow label="视频 ID">
            <Typography variant="body2" fontFamily="monospace" fontSize={12}>
              {comment.videoId}
            </Typography>
          </InfoRow>
        )}

        {/* User link */}
        {comment.userLink && (
          <InfoRow label="用户主页">
            <Link
              href={comment.userLink}
              target="_blank"
              rel="noopener noreferrer"
              underline="hover"
            >
              <Typography variant="body2" noWrap sx={{ maxWidth: 280 }}>
                {comment.userLink}
              </Typography>
            </Link>
          </InfoRow>
        )}
        {comment.userUid && (
          <InfoRow label="用户 UID">
            <Typography variant="body2" fontFamily="monospace" fontSize={12}>
              {comment.userUid}
            </Typography>
          </InfoRow>
        )}
      </Box>

      {/* Parent comment */}
      {comment.parentCommentContent && (
        <>
          <Divider sx={{ my: 2 }} />
          <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
            父评论
          </Typography>
          <Box
            sx={{
              p: 1.5,
              borderRadius: 2,
              bgcolor: 'action.hover',
              fontSize: 13,
              lineHeight: 1.6,
            }}
          >
            {comment.parentCommentContent}
          </Box>
          {comment.parentUserName && (
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              — {comment.parentUserName}
            </Typography>
          )}
        </>
      )}

      {/* Referenced comment */}
      {comment.refCommentContent && (
        <>
          <Divider sx={{ my: 2 }} />
          <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
            引用评论
          </Typography>
          <Box
            sx={{
              p: 1.5,
              borderRadius: 2,
              bgcolor: 'action.hover',
              fontSize: 13,
              lineHeight: 1.6,
            }}
          >
            {comment.refCommentContent}
          </Box>
          {comment.refUserName && (
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              — {comment.refUserName}
            </Typography>
          )}
        </>
      )}

      {/* Competitor flag */}
      {comment.isCompetitor && (
        <>
          <Divider sx={{ my: 2 }} />
          <Chip label="竞品评论" color="warning" size="small" />
        </>
      )}

      {/* Import info */}
      <Divider sx={{ my: 2 }} />
      <InfoRow label="导入时间">
        <Typography variant="body2" color="text.secondary">
          {comment.importedAt
            ? dayjs(comment.importedAt).format('YYYY-MM-DD HH:mm')
            : '—'}
        </Typography>
      </InfoRow>
      <InfoRow label="分析状态">
        <Chip
          label={comment.isAnalyzed ? '已分析' : '未分析'}
          size="small"
          color={comment.isAnalyzed ? 'success' : 'default'}
          variant="outlined"
          sx={{ fontSize: 11 }}
        />
      </InfoRow>
    </Drawer>
  );
};

export default CommentDetailDrawer;
