/**
 * Comment normalization utility — migrated from V1.
 *
 * Handles Chinese header field mapping, field validation,
 * and transformation from raw row objects to Comment objects.
 */

import type { Comment } from '../types/comment';
import { todayISO, nowISO } from './date';
import { nanoid } from 'nanoid';

/** Supported platforms */
const VALID_PLATFORMS = ['抖音', '小红书', 'B站', '视频号'];

/** Valid comment types */
const VALID_TYPES = ['barrier', 'demand', 'comparison', 'praise', 'complaint', 'intent'];

/** Valid sentiment values */
const VALID_SENTIMENTS = ['positive', 'neutral', 'negative'];

/** Valid categories */
const VALID_CATEGORIES = ['content', 'product'];

/**
 * Smart field mapper: tries multiple possible keys for a field.
 * Supports Chinese → English header mapping.
 */
function mapField(row: Record<string, unknown>, keys: string[]): string {
  for (const k of keys) {
    const val = row[k];
    if (val !== undefined && val !== null && val !== '') {
      return String(val).trim();
    }
  }
  return '';
}

/**
 * Normalize raw row data into Comment objects.
 *
 * @param rows - Array of raw row objects (from Excel/CSV/text)
 * @param brandId - Target brand ID
 * @param batchId - Import batch ID
 * @param startId - Starting comment ID (for incrementing from max existing)
 * @returns Normalized comments, errors, and total count
 */
export function normalizeComments(
  rows: Record<string, unknown>[],
  brandId: string,
  batchId: string,
  startId: number = 0,
): {
  comments: Comment[];
  errors: { row: number; errors: string[] }[];
  total: number;
} {
  const errors: { row: number; errors: string[] }[] = [];
  let nextId = startId;
  const importedAt = nowISO();

  const comments: Comment[] = rows.map((row, index) => {
    const rowErrors: string[] = [];

    // Core fields with Chinese alias support
    const content = mapField(row, ['content', '评论内容', 'text', 'comment', '内容']);
    if (!content) {
      rowErrors.push('缺少评论内容');
    }

    let platform = mapField(row, ['platform', '平台', 'source', '来源']) || '抖音';
    if (!VALID_PLATFORMS.includes(platform)) {
      platform = '抖音';
    }

    let category = (mapField(row, ['category', '分类', 'commentCategory']) || 'content').toLowerCase();
    if (!VALID_CATEGORIES.includes(category)) {
      category = 'content';
    }

    let type = (mapField(row, ['type', '评论类型', 'intent']) || 'demand').toLowerCase();
    if (!VALID_TYPES.includes(type)) {
      type = 'demand';
    }

    let sentiment = (mapField(row, ['sentiment', '情感', 'emotion']) || 'neutral').toLowerCase();
    if (!VALID_SENTIMENTS.includes(sentiment)) {
      sentiment = 'neutral';
    }

    // Labels parsing
    let labels: string[] = [];
    const labelStr = mapField(row, ['labels', '标签', 'tags']);
    if (labelStr) {
      if (labelStr.includes(',')) {
        labels = labelStr.split(',').map((l) => l.trim()).filter(Boolean);
      } else if (labelStr.includes('，')) {
        labels = labelStr.split('，').map((l) => l.trim()).filter(Boolean);
      } else {
        labels = [labelStr];
      }
    }

    // Competitor flag
    let isCompetitor = false;
    const compStr = (mapField(row, ['isCompetitor', '是否竞品', 'is_competitor']) || 'false').toLowerCase();
    isCompetitor = compStr === 'true' || compStr === 'yes' || compStr === '是';

    // Douyin-style fields
    const likes = parseInt(mapField(row, ['likes', '点赞量', 'likeCount', '点赞数'])) || 0;
    const commentTime = mapField(row, ['commentTime', '评论时间', 'created_at']) || '';
    const ipAddress = mapField(row, ['ipAddress', 'IP地址', 'ip', 'ip属地']) || '';
    const subCommentCount = parseInt(mapField(row, ['subCommentCount', '子评论数', 'replyCount', '回复数'])) || 0;
    const videoId = mapField(row, ['videoId', '视频ID', 'video_id']) || '';
    const videoLink = mapField(row, ['videoLink', '视频链接', 'video_url']) || '';
    const userUid = mapField(row, ['userUid', '用户UID', 'user_uid', 'uid']) || '';
    const userLink = mapField(row, ['userLink', '用户链接', 'user_url']) || '';
    const userName = mapField(row, ['userName', '用户名称', 'author', '用户', 'user', 'nickname']) || '匿名用户';
    const douyinId = mapField(row, ['douyinId', '抖音号', 'douyin_id', 'username']) || '';

    // Parent comment fields
    const parentCommentId = mapField(row, ['parentCommentId', '一级评论ID', 'parent_id']) || '';
    const parentCommentContent = mapField(row, ['parentCommentContent', '一级评论内容', 'parent_content']) || '';
    const parentUserUid = mapField(row, ['parentUserUid', '一级评论用户UID', 'parent_uid']) || '';
    const parentUserName = mapField(row, ['parentUserName', '一级评论用户名称', 'parent_username', 'parent_author']) || '';

    // Referenced comment fields
    const refCommentId = mapField(row, ['refCommentId', '引用的评论ID', 'ref_id', '引用评论ID']) || '';
    const refCommentContent = mapField(row, ['refCommentContent', '引用的评论内容', 'ref_content', '引用评论内容']) || '';
    const refUserUid = mapField(row, ['refUserUid', '引用的用户UID', 'ref_uid', '引用用户UID']) || '';
    const refUserName = mapField(row, ['refUserName', '引用的用户名称', 'ref_username', '引用用户名称']) || '';

    if (rowErrors.length > 0) {
      errors.push({ row: index + 1, errors: rowErrors });
    }

    const date = mapField(row, ['date', '日期', 'commentTime', '评论时间']) || todayISO();

    return {
      id: ++nextId,
      brandId,
      sourceHash: '',
      content,
      platform,
      category,
      type,
      sentiment,
      labels,
      author: userName,
      userName,
      douyinId,
      date,
      likes,
      commentTime,
      ipAddress,
      subCommentCount,
      videoId,
      videoLink,
      userUid,
      userLink,
      parentCommentId,
      parentCommentContent,
      parentUserUid,
      parentUserName,
      refCommentId,
      refCommentContent,
      refUserUid,
      refUserName,
      isCompetitor,
      competitorId: isCompetitor ? (parseInt(mapField(row, ['competitorId']) || '0') || null) : null,
      isAnalyzed: false,
      importedAt,
      importBatchId: batchId,
    };
  });

  return { comments, errors, total: comments.length };
}

/**
 * Parse CSV text into row objects
 */
export function parseCSV(
  text: string,
  delimiter?: string,
): Record<string, unknown>[] {
  const lines = text.trim().split('\n').filter((l) => l.trim());
  if (lines.length < 2) {
    throw new Error('CSV 至少需要表头 + 1行数据');
  }

  const delim = delimiter || detectDelimiter(lines[0]);
  const header = lines[0].split(delim).map((h) => h.trim().toLowerCase());
  const rows: Record<string, unknown>[] = [];

  for (let i = 1; i < lines.length; i++) {
    const cells = lines[i].split(delim);
    const row: Record<string, unknown> = {};
    cells.forEach((cell, j) => {
      if (j < header.length) row[header[j]] = cell.trim();
    });
    rows.push(row);
  }

  return rows;
}

/**
 * Auto-detect CSV delimiter
 */
export function detectDelimiter(line: string): string {
  if (line.includes('\t')) return '\t';
  if (line.includes(',')) return ',';
  return ',';
}
