/**
 * Date & week calculation utilities for VOS 2.0.
 */

import dayjs from 'dayjs';
import isoWeek from 'dayjs/plugin/isoWeek';

dayjs.extend(isoWeek);

/** Get the Monday (week start) date string for a given date */
export function getWeekStart(date?: string | Date): string {
  return dayjs(date).isoWeekday(1).format('YYYY-MM-DD');
}

/** Format an ISO date string for display */
export function formatDate(iso: string | null | undefined): string {
  if (!iso) return '—';
  return dayjs(iso).format('YYYY-MM-DD HH:mm');
}

/** Format date as short display (e.g., "07-11") */
export function formatDateShort(iso: string): string {
  return dayjs(iso).format('MM-DD');
}

/** Get today's ISO date string */
export function todayISO(): string {
  return new Date().toISOString().split('T')[0];
}

/** Get now as ISO 8601 UTC string */
export function nowISO(): string {
  return new Date().toISOString();
}
