/**
 * Chinese label mappings for comment types, sentiments, categories, and platforms.
 */

/** Comment type → Chinese display label */
export const COMMENT_TYPE_LABELS: Record<string, string> = {
  barrier: '使用障碍',
  demand: '需求建议',
  comparison: '竞品对比',
  praise: '好评',
  complaint: '投诉抱怨',
  intent: '购买意向',
};

/** Sentiment → Chinese display label */
export const SENTIMENT_LABELS: Record<string, string> = {
  positive: '正面',
  neutral: '中性',
  negative: '负面',
};

/** Comment category → Chinese display label */
export const CATEGORY_LABELS: Record<string, string> = {
  content: '内容',
  product: '产品',
};

/** Type → MUI Chip color mapping */
export const COMMENT_TYPE_COLORS: Record<string, 'default' | 'primary' | 'success' | 'warning' | 'error' | 'info'> = {
  barrier: 'warning',
  demand: 'info',
  comparison: 'default',
  praise: 'success',
  complaint: 'error',
  intent: 'primary',
};

/** Sentiment → MUI Chip color mapping */
export const SENTIMENT_COLORS: Record<string, 'default' | 'success' | 'warning' | 'error'> = {
  positive: 'success',
  neutral: 'default',
  negative: 'error',
};

/** All comment type options for filter dropdowns */
export const COMMENT_TYPE_OPTIONS = Object.entries(COMMENT_TYPE_LABELS).map(
  ([value, label]) => ({ value, label }),
);

/** All sentiment options for filter dropdowns */
export const SENTIMENT_OPTIONS = Object.entries(SENTIMENT_LABELS).map(
  ([value, label]) => ({ value, label }),
);

/** All category options for filter dropdowns */
export const CATEGORY_OPTIONS = Object.entries(CATEGORY_LABELS).map(
  ([value, label]) => ({ value, label }),
);
