import React from 'react';
import {
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Typography,
  Chip,
  Box,
} from '@mui/material';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import ContentCopyIcon from '@mui/icons-material/ContentCopy';
import ErrorOutlineIcon from '@mui/icons-material/ErrorOutline';
import type { ImportHistory } from '@/shared/types/comment';
import dayjs from 'dayjs';

interface ImportHistoryListProps {
  history: ImportHistory[];
}

/** Display import history records in a table */
const ImportHistoryList: React.FC<ImportHistoryListProps> = ({ history }) => {
  if (history.length === 0) {
    return (
      <Box sx={{ py: 4, textAlign: 'center' }}>
        <Typography color="text.secondary" variant="body2">
          暂无导入记录
        </Typography>
      </Box>
    );
  }

  return (
    <TableContainer
      component={Paper}
      variant="outlined"
      sx={{ maxHeight: 400 }}
    >
      <Table size="small" stickyHeader>
        <TableHead>
          <TableRow>
            <TableCell sx={{ fontWeight: 600 }}>时间</TableCell>
            <TableCell sx={{ fontWeight: 600 }}>文件名</TableCell>
            <TableCell sx={{ fontWeight: 600 }}>平台</TableCell>
            <TableCell sx={{ fontWeight: 600 }} align="center">
              总数
            </TableCell>
            <TableCell sx={{ fontWeight: 600 }} align="center">
              导入
            </TableCell>
            <TableCell sx={{ fontWeight: 600 }} align="center">
              去重
            </TableCell>
            <TableCell sx={{ fontWeight: 600 }} align="center">
              错误
            </TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {history.map((record) => (
            <TableRow key={record.id} hover>
              <TableCell>
                <Typography variant="body2" noWrap>
                  {dayjs(record.timestamp).format('MM-DD HH:mm')}
                </Typography>
              </TableCell>
              <TableCell>
                <Typography variant="body2" noWrap sx={{ maxWidth: 160 }}>
                  {record.fileName || record.source || '—'}
                </Typography>
              </TableCell>
              <TableCell>
                <Box sx={{ display: 'flex', gap: 0.5, flexWrap: 'wrap' }}>
                  {(record.platforms || []).map((p) => (
                    <Chip
                      key={p}
                      label={p}
                      size="small"
                      variant="outlined"
                      sx={{ fontSize: 10, height: 20 }}
                    />
                  ))}
                  {(!record.platforms || record.platforms.length === 0) && (
                    <Typography variant="body2" color="text.secondary">
                      —
                    </Typography>
                  )}
                </Box>
              </TableCell>
              <TableCell align="center">
                <Typography variant="body2">{record.totalRows}</Typography>
              </TableCell>
              <TableCell align="center">
                <Box
                  sx={{
                    display: 'inline-flex',
                    alignItems: 'center',
                    gap: 0.3,
                  }}
                >
                  <CheckCircleIcon sx={{ fontSize: 14, color: 'success.main' }} />
                  <Typography variant="body2" color="success.main" fontWeight={600}>
                    {record.imported}
                  </Typography>
                </Box>
              </TableCell>
              <TableCell align="center">
                <Box
                  sx={{
                    display: 'inline-flex',
                    alignItems: 'center',
                    gap: 0.3,
                  }}
                >
                  <ContentCopyIcon
                    sx={{ fontSize: 14, color: 'warning.main' }}
                  />
                  <Typography variant="body2" color="warning.main">
                    {record.duplicated}
                  </Typography>
                </Box>
              </TableCell>
              <TableCell align="center">
                <Box
                  sx={{
                    display: 'inline-flex',
                    alignItems: 'center',
                    gap: 0.3,
                  }}
                >
                  {record.errors > 0 ? (
                    <>
                      <ErrorOutlineIcon
                        sx={{ fontSize: 14, color: 'error.main' }}
                      />
                      <Typography variant="body2" color="error.main">
                        {record.errors}
                      </Typography>
                    </>
                  ) : (
                    <Typography variant="body2" color="text.secondary">
                      0
                    </Typography>
                  )}
                </Box>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </TableContainer>
  );
};

export default ImportHistoryList;
