import React, { useState, useCallback, useRef } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Tabs,
  Tab,
  Box,
  Typography,
  TextField,
  FormControlLabel,
  Checkbox,
  Alert,
  LinearProgress,
  Chip,
  Divider,
  Paper,
} from '@mui/material';
import CloudUploadIcon from '@mui/icons-material/CloudUpload';
import ContentPasteIcon from '@mui/icons-material/ContentPaste';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import * as XLSX from 'xlsx';
import type { Comment, ImportHistory } from '@/shared/types/comment';
import { normalizeComments, parseCSV } from '@/shared/utils/normalizeComments';
import { PLATFORMS } from '@/shared/constants/platforms';

interface ImportDialogProps {
  open: boolean;
  brandId: string;
  onClose: () => void;
  onImport: (
    comments: Comment[],
    importMeta: Omit<ImportHistory, 'id'>,
  ) => Promise<{ imported: number; duplicated: number; errors: number }>;
}

interface PreviewData {
  comments: Comment[];
  errors: { row: number; errors: string[] }[];
}

/** Format file size for display */
function formatFileSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

/** Import dialog with file upload and text paste */
const ImportDialog: React.FC<ImportDialogProps> = ({
  open,
  brandId,
  onClose,
  onImport,
}) => {
  const [tab, setTab] = useState(0);
  const [autoDedup, setAutoDedup] = useState(true);
  const [autoAnalyze, setAutoAnalyze] = useState(false);
  const [importing, setImporting] = useState(false);
  const [preview, setPreview] = useState<PreviewData | null>(null);
  const [result, setResult] = useState<{
    imported: number;
    duplicated: number;
    errors: number;
  } | null>(null);

  // File upload state
  const [dragOver, setDragOver] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Text paste state
  const [pasteText, setPasteText] = useState('');
  const [pasteDelimiter, setPasteDelimiter] = useState(',');

  // Reset state when dialog opens/closes
  const handleClose = () => {
    setPreview(null);
    setResult(null);
    setSelectedFile(null);
    setFileError('');
    setPasteText('');
    setImporting(false);
    onClose();
  };

  /** Parse file data into preview */
  const parseFileData = useCallback(
    (data: Record<string, unknown>[], fileName: string) => {
      const maxId = 0; // Will be assigned by commentStore
      const batchId = `preview_${Date.now()}`;
      const normalized = normalizeComments(data, brandId, batchId, maxId);

      if (normalized.comments.length === 0) {
        setFileError('未能解析到有效评论数据，请检查文件格式');
        return;
      }

      setPreview(normalized);
      setFileError('');

      // Auto-enable AI analysis if >= 20 comments
      if (normalized.comments.length >= 20) {
        setAutoAnalyze(true);
      }
    },
    [brandId],
  );

  /** Handle file drop */
  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      setDragOver(false);
      const file = e.dataTransfer.files[0];
      if (file) {
        processFile(file);
      }
    },
    [brandId],
  );

  /** Process uploaded file */
  const processFile = async (file: File) => {
    setSelectedFile(file);
    setFileError('');
    setPreview(null);

    const ext = file.name.split('.').pop()?.toLowerCase();

    try {
      if (ext === 'json') {
        const text = await file.text();
        const data = JSON.parse(text);
        const rows = Array.isArray(data) ? data : [data];
        parseFileData(rows, file.name);
      } else if (ext === 'xlsx' || ext === 'xls') {
        const buffer = await file.arrayBuffer();
        const workbook = XLSX.read(buffer, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        const rows = XLSX.utils.sheet_to_json<Record<string, unknown>>(sheet);
        parseFileData(rows, file.name);
      } else if (ext === 'csv') {
        const text = await file.text();
        const rows = parseCSV(text);
        parseFileData(rows, file.name);
      } else {
        setFileError(`不支持的文件格式：.${ext}，请使用 .xlsx .csv .json`);
      }
    } catch (err) {
      setFileError(
        `文件解析失败：${err instanceof Error ? err.message : '未知错误'}`,
      );
    }
  };

  /** Handle file input change */
  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  /** Handle text paste parse */
  const handleParseText = () => {
    if (!pasteText.trim()) {
      setFileError('请输入要导入的数据');
      return;
    }
    try {
      const rows = parseCSV(pasteText, pasteDelimiter);
      parseFileData(rows, '手动粘贴');
    } catch (err) {
      setFileError(
        `文本解析失败：${err instanceof Error ? err.message : '未知错误'}`,
      );
    }
  };

  /** Execute import */
  const handleImport = async () => {
    if (!preview || preview.comments.length === 0) return;

    setImporting(true);
    try {
      const platforms = [
        ...new Set(preview.comments.map((c) => c.platform).filter(Boolean)),
      ];
      const importMeta: Omit<ImportHistory, 'id'> = {
        brandId,
        timestamp: new Date().toISOString(),
        source: selectedFile?.name || '手动粘贴',
        fileName: selectedFile?.name || '',
        platforms,
        totalRows: preview.total,
        imported: 0,
        duplicated: 0,
        errors: preview.errors.length,
      };

      const importResult = await onImport(preview.comments, importMeta);
      setResult(importResult);
    } catch (err) {
      setFileError(
        `导入失败：${err instanceof Error ? err.message : '未知错误'}`,
      );
    } finally {
      setImporting(false);
    }
  };

  return (
    <Dialog
      open={open}
      onClose={importing ? undefined : handleClose}
      maxWidth="md"
      fullWidth
      PaperProps={{ sx: { borderRadius: 3, minHeight: 500 } }}
    >
      <DialogTitle sx={{ fontWeight: 700 }}>导入评论数据</DialogTitle>

      <Tabs
        value={tab}
        onChange={(_, v) => {
          setTab(v);
          setPreview(null);
          setFileError('');
        }}
        sx={{ borderBottom: 1, borderColor: 'divider', px: 2 }}
      >
        <Tab icon={<CloudUploadIcon />} label="文件上传" iconPosition="start" />
        <Tab
          icon={<ContentPasteIcon />}
          label="粘贴导入"
          iconPosition="start"
        />
      </Tabs>

      <DialogContent sx={{ pt: 2 }}>
        {/* Tab 0: File Upload */}
        {tab === 0 && (
          <Box>
            {/* Drop zone */}
            <Paper
              variant="outlined"
              onDragOver={(e) => {
                e.preventDefault();
                setDragOver(true);
              }}
              onDragLeave={() => setDragOver(false)}
              onDrop={handleDrop}
              sx={{
                p: 4,
                textAlign: 'center',
                cursor: 'pointer',
                borderStyle: 'dashed',
                borderColor: dragOver ? 'primary.main' : 'divider',
                bgcolor: dragOver ? 'action.hover' : 'transparent',
                transition: 'all 0.2s',
                mb: 2,
              }}
              onClick={() => fileInputRef.current?.click()}
            >
              <CloudUploadIcon
                sx={{ fontSize: 48, color: 'text.secondary', mb: 1 }}
              />
              <Typography variant="body1" fontWeight={500}>
                拖拽文件到此处，或点击选择文件
              </Typography>
              <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
                支持 .xlsx .csv .json 格式
              </Typography>
              <input
                ref={fileInputRef}
                type="file"
                hidden
                accept=".xlsx,.xls,.csv,.json"
                onChange={handleFileSelect}
              />
            </Paper>

            {/* Selected file info */}
            {selectedFile && (
              <Paper variant="outlined" sx={{ p: 2, mb: 2 }}>
                <Box
                  sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1 }}
                >
                  <Typography variant="body2" fontWeight={600}>
                    {selectedFile.name}
                  </Typography>
                  <Chip
                    label={formatFileSize(selectedFile.size)}
                    size="small"
                    variant="outlined"
                  />
                </Box>
              </Paper>
            )}

            {fileError && (
              <Alert severity="error" sx={{ mb: 2 }}>
                {fileError}
              </Alert>
            )}
          </Box>
        )}

        {/* Tab 1: Text Paste */}
        {tab === 1 && (
          <Box>
            <Box
              sx={{ display: 'flex', alignItems: 'center', gap: 2, mb: 1.5 }}
            >
              <Typography variant="body2" color="text.secondary">
                分隔符：
              </Typography>
              {[',', '\t', '|'].map((d) => (
                <Chip
                  key={d}
                  label={d === '\t' ? 'Tab' : d}
                  size="small"
                  variant={pasteDelimiter === d ? 'filled' : 'outlined'}
                  color={pasteDelimiter === d ? 'primary' : 'default'}
                  onClick={() => setPasteDelimiter(d)}
                />
              ))}
            </Box>
            <TextField
              multiline
              minRows={6}
              maxRows={14}
              fullWidth
              value={pasteText}
              onChange={(e) => setPasteText(e.target.value)}
              placeholder={`第一行为表头：平台,评论内容,评论类型,情感,日期,作者,...\n抖音,这个产品太好用了,praise,positive,2024-01-15,用户A`}
              sx={{ mb: 2 }}
            />
            <Button
              variant="outlined"
              onClick={handleParseText}
              disabled={!pasteText.trim()}
            >
              解析数据
            </Button>
            {fileError && (
              <Alert severity="error" sx={{ mt: 2 }}>
                {fileError}
              </Alert>
            )}
          </Box>
        )}

        {/* Preview section */}
        {preview && !result && (
          <>
            <Divider sx={{ my: 2 }} />
            <Typography variant="subtitle2" fontWeight={600} sx={{ mb: 1 }}>
              解析预览
            </Typography>
            <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap', mb: 2 }}>
              <Chip
                icon={<CheckCircleIcon />}
                label={`${preview.comments.length} 条有效评论`}
                color="success"
                variant="outlined"
              />
              {preview.errors.length > 0 && (
                <Chip
                  label={`${preview.errors.length} 行有错误`}
                  color="warning"
                  variant="outlined"
                />
              )}
              <Chip
                label={`平台：${[...new Set(preview.comments.map((c) => c.platform))].join('、') || '—'}`}
                variant="outlined"
              />
            </Box>

            {/* Preview table (first 5 items) */}
            <Paper variant="outlined" sx={{ maxHeight: 200, overflow: 'auto' }}>
              <Box sx={{ p: 1, display: 'flex', flexDirection: 'column', gap: 0.5 }}>
                {preview.comments.slice(0, 5).map((c, i) => (
                  <Box
                    key={i}
                    sx={{
                      display: 'flex',
                      gap: 1,
                      alignItems: 'flex-start',
                      py: 0.5,
                    }}
                  >
                    <Chip
                      label={c.platform}
                      size="small"
                      variant="outlined"
                      sx={{ fontSize: 10, height: 20, flexShrink: 0 }}
                    />
                    <Typography variant="body2" noWrap sx={{ flexGrow: 1 }}>
                      {c.content.substring(0, 80)}
                      {c.content.length > 80 ? '…' : ''}
                    </Typography>
                  </Box>
                ))}
                {preview.comments.length > 5 && (
                  <Typography variant="body2" color="text.secondary" sx={{ textAlign: 'center', py: 0.5 }}>
                    ... 还有 {preview.comments.length - 5} 条 ...
                  </Typography>
                )}
              </Box>
            </Paper>
          </>
        )}

        {/* Result section */}
        {result && (
          <>
            <Divider sx={{ my: 2 }} />
            <Alert severity="success" variant="outlined">
              <Typography variant="body2" fontWeight={600}>
                导入完成
              </Typography>
              <Typography variant="body2">
                成功 {result.imported} 条，跳过 {result.duplicated} 条重复
                {result.errors > 0 && `，${result.errors} 条错误`}
              </Typography>
            </Alert>
          </>
        )}

        {/* Import options */}
        <Divider sx={{ my: 2 }} />
        <Typography variant="subtitle2" fontWeight={600} sx={{ mb: 1 }}>
          导入选项
        </Typography>
        <FormControlLabel
          control={
            <Checkbox
              checked={autoDedup}
              onChange={(e) => setAutoDedup(e.target.checked)}
            />
          }
          label="自动去重（基于视频ID+用户UID+内容前50字）"
        />
        <br />
        <FormControlLabel
          control={
            <Checkbox
              checked={autoAnalyze}
              onChange={(e) => setAutoAnalyze(e.target.checked)}
            />
          }
          label="导入后自动启动 AI 分析（≥20条时建议开启）"
        />
      </DialogContent>

      <DialogActions sx={{ px: 3, py: 2 }}>
        {importing && <LinearProgress sx={{ flexGrow: 1, mr: 2 }} />}
        <Button onClick={handleClose} color="inherit" disabled={importing}>
          {result ? '关闭' : '取消'}
        </Button>
        {!result && (
          <Button
            onClick={handleImport}
            variant="contained"
            disabled={!preview || preview.comments.length === 0 || importing}
          >
            {importing ? '导入中...' : `确认导入 (${preview?.comments.length || 0} 条)`}
          </Button>
        )}
      </DialogActions>
    </Dialog>
  );
};

export default ImportDialog;
