import React, { useEffect, useState, useCallback, useMemo } from 'react';
import {
  Box,
  Typography,
  TextField,
  Button,
  MenuItem,
  Stack,
  Tabs,
  Tab,
  Chip,
  IconButton,
  Tooltip,
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import UploadFileIcon from '@mui/icons-material/UploadFile';
import HistoryIcon from '@mui/icons-material/History';
import ClearIcon from '@mui/icons-material/Clear';
import { useBrandStore } from '@/shared/stores/brandStore';
import { useCommentStore } from '@/shared/stores/commentStore';
import { PLATFORM_OPTIONS } from '@/shared/constants/platforms';
import {
  COMMENT_TYPE_OPTIONS,
  SENTIMENT_OPTIONS,
  COMMENT_TYPE_LABELS,
  SENTIMENT_LABELS,
} from '@/shared/constants/labels';
import CommentTable from './CommentTable';
import CommentDetailDrawer from './CommentDetailDrawer';
import ImportDialog from './ImportDialog';
import ImportHistoryList from './ImportHistoryList';
import type { Comment, ImportHistory } from '@/shared/types/comment';

/** Active filters count badge */
const FilterBadge: React.FC<{ count: number }> = ({ count }) => {
  if (count === 0) return null;
  return (
    <Chip
      label={count}
      size="small"
      color="primary"
      sx={{ ml: 0.5, height: 18, fontSize: 11 }}
    />
  );
};

/** Comment Pool page with table, filters, import and detail view */
const CommentPoolPage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const {
    comments,
    totalCount,
    page,
    pageSize,
    filters,
    importHistory,
    isLoading,
    loadComments,
    loadImportHistory,
    importComments,
    setFilter,
    setPage,
    setPageSize,
  } = useCommentStore();

  // Local state
  const [searchInput, setSearchInput] = useState('');
  const [detailOpen, setDetailOpen] = useState(false);
  const [selectedComment, setSelectedComment] = useState<Comment | null>(null);
  const [importOpen, setImportOpen] = useState(false);
  const [tabValue, setTabValue] = useState(0);
  const [debounceTimer, setDebounceTimer] = useState<ReturnType<typeof setTimeout> | null>(null);

  // Load comments when brand changes
  useEffect(() => {
    if (currentBrandId) {
      loadComments(currentBrandId);
      loadImportHistory(currentBrandId);
    }
  }, [currentBrandId, loadComments, loadImportHistory]);

  // Debounced search
  const handleSearchChange = useCallback(
    (value: string) => {
      setSearchInput(value);
      if (debounceTimer) clearTimeout(debounceTimer);
      const timer = setTimeout(() => {
        setFilter('search', value);
      }, 300);
      setDebounceTimer(timer);
    },
    [debounceTimer, setFilter],
  );

  // Clear all filters
  const clearFilters = () => {
    setFilter('platform', '');
    setFilter('type', '');
    setFilter('sentiment', '');
    setFilter('category', '');
    setFilter('search', '');
    setSearchInput('');
  };

  // Count active filters
  const activeFilterCount = useMemo(() => {
    let count = 0;
    if (filters.platform) count++;
    if (filters.type) count++;
    if (filters.sentiment) count++;
    if (filters.category) count++;
    if (filters.search) count++;
    return count;
  }, [filters]);

  // Filtered comments (server-side filter in store, but we do client-side here for paginated view)
  const filteredComments = useMemo(() => {
    let result = [...comments];

    // Apply filters
    if (filters.platform) {
      result = result.filter((c) => c.platform === filters.platform);
    }
    if (filters.type) {
      result = result.filter((c) => c.type === filters.type);
    }
    if (filters.sentiment) {
      result = result.filter((c) => c.sentiment === filters.sentiment);
    }
    if (filters.category) {
      result = result.filter((c) => c.category === filters.category);
    }
    if (filters.search) {
      const q = filters.search.toLowerCase();
      result = result.filter(
        (c) =>
          c.content.toLowerCase().includes(q) ||
          (c.userName || '').toLowerCase().includes(q) ||
          (c.platform || '').toLowerCase().includes(q),
      );
    }

    return result;
  }, [comments, filters]);

  const handleRowClick = (comment: Comment) => {
    setSelectedComment(comment);
    setDetailOpen(true);
  };

  const handleImport = async (
    newComments: Comment[],
    importMeta: Omit<ImportHistory, 'id'>,
  ) => {
    if (!currentBrandId) {
      throw new Error('请先选择品牌');
    }
    const result = await importComments(currentBrandId, newComments, importMeta);
    // Reload brand store to update stats
    useBrandStore.getState().loadBrands();
    return result;
  };

  if (!currentBrandId) {
    return (
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          height: '100%',
        }}
      >
        <Typography color="text.secondary">请先选择品牌</Typography>
      </Box>
    );
  }

  return (
    <Box>
      {/* Page header */}
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          mb: 2,
        }}
      >
        <Box>
          <Typography variant="h5" fontWeight={700}>
            评论池
          </Typography>
          <Typography variant="body2" color="text.secondary">
            共 {totalCount} 条评论
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<UploadFileIcon />}
          onClick={() => setImportOpen(true)}
        >
          导入评论
        </Button>
      </Box>

      {/* Tabs */}
      <Tabs
        value={tabValue}
        onChange={(_, v) => setTabValue(v)}
        sx={{ mb: 2, borderBottom: 1, borderColor: 'divider' }}
      >
        <Tab label="评论列表" />
        <Tab
          label={
            <Box sx={{ display: 'flex', alignItems: 'center' }}>
              <HistoryIcon sx={{ fontSize: 18, mr: 0.5 }} />
              导入历史
            </Box>
          }
        />
      </Tabs>

      {/* Tab 0: Comments */}
      {tabValue === 0 && (
        <>
          {/* Filters */}
          <Paper
            variant="outlined"
            sx={{ p: 1.5, mb: 2, display: 'flex', gap: 1.5, flexWrap: 'wrap', alignItems: 'center' }}
          >
            <TextField
              size="small"
              placeholder="搜索评论内容、作者、平台..."
              value={searchInput}
              onChange={(e) => handleSearchChange(e.target.value)}
              sx={{ minWidth: 240, flexGrow: 1 }}
              InputProps={{
                endAdornment: searchInput ? (
                  <IconButton
                    size="small"
                    onClick={() => {
                      handleSearchChange('');
                      setFilter('search', '');
                    }}
                  >
                    <ClearIcon fontSize="small" />
                  </IconButton>
                ) : undefined,
              }}
            />
            <TextField
              select
              size="small"
              label="平台"
              value={filters.platform}
              onChange={(e) => setFilter('platform', e.target.value)}
              sx={{ minWidth: 110 }}
            >
              <MenuItem value="">全部</MenuItem>
              {PLATFORM_OPTIONS.map((opt) => (
                <MenuItem key={opt.value} value={opt.value}>
                  {opt.label}
                </MenuItem>
              ))}
            </TextField>
            <TextField
              select
              size="small"
              label="类型"
              value={filters.type}
              onChange={(e) => setFilter('type', e.target.value)}
              sx={{ minWidth: 110 }}
            >
              <MenuItem value="">全部</MenuItem>
              {COMMENT_TYPE_OPTIONS.map((opt) => (
                <MenuItem key={opt.value} value={opt.value}>
                  {opt.label}
                </MenuItem>
              ))}
            </TextField>
            <TextField
              select
              size="small"
              label="情感"
              value={filters.sentiment}
              onChange={(e) => setFilter('sentiment', e.target.value)}
              sx={{ minWidth: 100 }}
            >
              <MenuItem value="">全部</MenuItem>
              {SENTIMENT_OPTIONS.map((opt) => (
                <MenuItem key={opt.value} value={opt.value}>
                  {opt.label}
                </MenuItem>
              ))}
            </TextField>
            {activeFilterCount > 0 && (
              <Button
                size="small"
                color="inherit"
                startIcon={<ClearIcon />}
                onClick={clearFilters}
              >
                清除筛选
                <FilterBadge count={activeFilterCount} />
              </Button>
            )}
          </Paper>

          {/* Comment table */}
          <CommentTable
            comments={filteredComments}
            page={page}
            pageSize={pageSize}
            totalCount={filteredComments.length}
            onPageChange={setPage}
            onPageSizeChange={setPageSize}
            onRowClick={handleRowClick}
          />
        </>
      )}

      {/* Tab 1: Import History */}
      {tabValue === 1 && (
        <ImportHistoryList history={importHistory} />
      )}

      {/* Import dialog */}
      <ImportDialog
        open={importOpen}
        brandId={currentBrandId}
        onClose={() => setImportOpen(false)}
        onImport={handleImport}
      />

      {/* Comment detail drawer */}
      <CommentDetailDrawer
        open={detailOpen}
        comment={selectedComment}
        onClose={() => {
          setDetailOpen(false);
          setSelectedComment(null);
        }}
      />
    </Box>
  );
};

export default CommentPoolPage;
