import React, { useMemo, useState } from 'react';
import {
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TablePagination,
  TableSortLabel,
  Paper,
  Chip,
  Typography,
  Box,
} from '@mui/material';
import type { Comment } from '@/shared/types/comment';
import { COMMENT_TYPE_LABELS, COMMENT_TYPE_COLORS, SENTIMENT_COLORS } from '@/shared/constants/labels';
import dayjs from 'dayjs';

interface CommentTableProps {
  comments: Comment[];
  page: number;
  pageSize: number;
  totalCount: number;
  onPageChange: (page: number) => void;
  onPageSizeChange: (pageSize: number) => void;
  onRowClick: (comment: Comment) => void;
}

type SortField = 'platform' | 'userName' | 'type' | 'sentiment' | 'date' | 'likes';
type SortDir = 'asc' | 'desc';

/** Sortable table for displaying comment list */
const CommentTable: React.FC<CommentTableProps> = ({
  comments,
  page,
  pageSize,
  totalCount,
  onPageChange,
  onPageSizeChange,
  onRowClick,
}) => {
  const [sortField, setSortField] = useState<SortField>('date');
  const [sortDir, setSortDir] = useState<SortDir>('desc');

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortDir((prev) => (prev === 'asc' ? 'desc' : 'asc'));
    } else {
      setSortField(field);
      setSortDir('desc');
    }
  };

  const sortedComments = useMemo(() => {
    const sorted = [...comments];
    sorted.sort((a, b) => {
      let cmp = 0;
      switch (sortField) {
        case 'platform':
          cmp = (a.platform || '').localeCompare(b.platform || '');
          break;
        case 'userName':
          cmp = (a.userName || '').localeCompare(b.userName || '');
          break;
        case 'type':
          cmp = (a.type || '').localeCompare(b.type || '');
          break;
        case 'sentiment':
          cmp = (a.sentiment || '').localeCompare(b.sentiment || '');
          break;
        case 'date':
          cmp = new Date(a.date || 0).getTime() - new Date(b.date || 0).getTime();
          break;
        case 'likes':
          cmp = (a.likes || 0) - (b.likes || 0);
          break;
      }
      return sortDir === 'asc' ? cmp : -cmp;
    });
    return sorted;
  }, [comments, sortField, sortDir]);

  const paginatedComments = useMemo(() => {
    const start = (page - 1) * pageSize;
    return sortedComments.slice(start, start + pageSize);
  }, [sortedComments, page, pageSize]);

  const columns: { field: SortField; label: string; width?: number }[] = [
    { field: 'platform', label: '平台', width: 80 },
    { field: 'userName', label: '作者', width: 120 },
    { field: 'type', label: '类型', width: 90 },
    { field: 'sentiment', label: '情感', width: 70 },
    { field: 'date', label: '时间', width: 110 },
    { field: 'likes', label: '点赞', width: 60 },
  ];

  const truncate = (text: string, maxLen: number = 60): string => {
    if (!text) return '';
    return text.length > maxLen ? text.substring(0, maxLen) + '…' : text;
  };

  return (
    <Paper sx={{ width: '100%', overflow: 'hidden' }} variant="outlined">
      <TableContainer sx={{ maxHeight: 'calc(100vh - 360px)' }}>
        <Table stickyHeader size="small">
          <TableHead>
            <TableRow>
              {columns.map((col) => (
                <TableCell
                  key={col.field}
                  sx={{
                    width: col.width,
                    fontWeight: 600,
                    bgcolor: 'background.paper',
                  }}
                >
                  <TableSortLabel
                    active={sortField === col.field}
                    direction={sortField === col.field ? sortDir : 'asc'}
                    onClick={() => handleSort(col.field)}
                  >
                    {col.label}
                  </TableSortLabel>
                </TableCell>
              ))}
              <TableCell sx={{ fontWeight: 600, bgcolor: 'background.paper' }}>
                内容摘要
              </TableCell>
              <TableCell sx={{ width: 120, fontWeight: 600, bgcolor: 'background.paper' }}>
                标签
              </TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {paginatedComments.length === 0 ? (
              <TableRow>
                <TableCell colSpan={8} align="center" sx={{ py: 6 }}>
                  <Typography color="text.secondary" variant="body2">
                    暂无评论数据
                  </Typography>
                </TableCell>
              </TableRow>
            ) : (
              paginatedComments.map((comment) => (
                <TableRow
                  key={comment.id}
                  hover
                  onClick={() => onRowClick(comment)}
                  sx={{ cursor: 'pointer' }}
                >
                  <TableCell>
                    <Chip
                      label={comment.platform}
                      size="small"
                      variant="outlined"
                      sx={{ fontSize: 11 }}
                    />
                  </TableCell>
                  <TableCell>
                    <Typography variant="body2" fontWeight={500} noWrap>
                      {comment.userName || '匿名用户'}
                    </Typography>
                  </TableCell>
                  <TableCell>
                    <Chip
                      label={COMMENT_TYPE_LABELS[comment.type] || comment.type}
                      size="small"
                      color={COMMENT_TYPE_COLORS[comment.type] || 'default'}
                      sx={{ fontSize: 11 }}
                    />
                  </TableCell>
                  <TableCell>
                    <Chip
                      label={
                        comment.sentiment === 'positive'
                          ? '正面'
                          : comment.sentiment === 'negative'
                            ? '负面'
                            : '中性'
                      }
                      size="small"
                      color={SENTIMENT_COLORS[comment.sentiment] || 'default'}
                      variant="outlined"
                      sx={{ fontSize: 11 }}
                    />
                  </TableCell>
                  <TableCell>
                    <Typography variant="body2" color="text.secondary" noWrap>
                      {comment.date ? dayjs(comment.date).format('MM-DD HH:mm') : '—'}
                    </Typography>
                  </TableCell>
                  <TableCell align="right">
                    <Typography variant="body2">{comment.likes || 0}</Typography>
                  </TableCell>
                  <TableCell>
                    <Typography variant="body2" color="text.secondary" noWrap>
                      {truncate(comment.content)}
                    </Typography>
                  </TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', gap: 0.3, flexWrap: 'wrap' }}>
                      {(comment.labels || []).slice(0, 2).map((label) => (
                        <Chip
                          key={label}
                          label={label}
                          size="small"
                          variant="outlined"
                          sx={{ fontSize: 10, height: 20 }}
                        />
                      ))}
                      {(comment.labels || []).length > 2 && (
                        <Chip
                          label={`+${comment.labels.length - 2}`}
                          size="small"
                          sx={{ fontSize: 10, height: 20 }}
                        />
                      )}
                    </Box>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </TableContainer>
      <TablePagination
        component="div"
        count={totalCount}
        page={page - 1}
        onPageChange={(_, newPage) => onPageChange(newPage + 1)}
        rowsPerPage={pageSize}
        onRowsPerPageChange={(e) => onPageSizeChange(Number(e.target.value))}
        rowsPerPageOptions={[20, 50, 100, 200]}
        labelRowsPerPage="每页："
        labelDisplayedRows={({ from, to, count }) =>
          `${from}-${to} / 共 ${count} 条`
        }
      />
    </Paper>
  );
};

export default CommentTable;
